const req = $input.first().json || {};
const expected = String($env.APP_INTERNAL_TOKEN || '').trim();
const headers = req.headers || {};
const rawToken = headers['x-internal-token'] || headers['X-Internal-Token'] || headers['x_internal_token'] || '';
const token = Array.isArray(rawToken) ? String(rawToken[0] || '').trim() : String(rawToken || '').trim();

if (!expected) {
  return [{ json: { ok: false, statusCode: 500, error: 'APP_INTERNAL_TOKEN is not configured in n8n' } }];
}

if (token !== expected) {
  return [{ json: { ok: false, statusCode: 403, error: 'Unauthorized token' } }];
}

return [{ json: { ok: true, statusCode: 200, payload: req.body || req } }];

const incoming = $input.first().json || {};
const payload = incoming.payload || {};

const required = ['alert_id', 'entry_id', 'order_code', 'customer_name', 'status', 'deadline_at', 'checked_at', 'target', 'contact'];
const missing = required.filter((k) => payload[k] === undefined || payload[k] === null || String(payload[k]).trim() === '');
if (missing.length > 0) {
  return [{ json: { ok: false, statusCode: 400, error: `Missing required fields: ${missing.join(', ')}` } }];
}

const target = String(payload.target || '').trim().toUpperCase();
if (!['GIRI', 'MD'].includes(target)) {
  return [{ json: { ok: false, statusCode: 400, error: 'Invalid target. Allowed values: GIRI, MD' } }];
}

const normalized = {
  alert_id: String(payload.alert_id),
  entry_id: Number(payload.entry_id),
  order_code: String(payload.order_code),
  customer_name: String(payload.customer_name),
  status: String(payload.status),
  deadline_at: String(payload.deadline_at),
  checked_at: String(payload.checked_at),
  target,
  contact: String(payload.contact).replace(/[^0-9]/g, '')
};

if (!normalized.contact) {
  return [{ json: { ok: false, statusCode: 400, error: 'Invalid contact format' } }];
}

return [{ json: { ok: true, statusCode: 200, normalized } }];

const normalized = $input.first().json.normalized;
const graphVersion = String($env.META_GRAPH_VERSION || 'v19.0').trim();
const phoneNumberId = String($env.WHATSAPP_PHONE_NUMBER_ID || '').trim();
if (!phoneNumberId) {
  return [{ json: { ok: false, statusCode: 500, error: 'WHATSAPP_PHONE_NUMBER_ID is not configured' } }];
}

const templateName = normalized.target === 'GIRI'
  ? String($env.WORK_TIMING_TEMPLATE_GIRI || 'work_timing_overdue_giri_v1')
  : String($env.WORK_TIMING_TEMPLATE_MD || 'work_timing_overdue_md_v1');

const requestBody = {
  messaging_product: 'whatsapp',
  to: normalized.contact,
  type: 'template',
  template: {
    name: templateName,
    language: { code: 'en_US' },
    components: [
      {
        type: 'body',
        parameters: [
          { type: 'text', text: normalized.order_code },
          { type: 'text', text: normalized.customer_name },
          { type: 'text', text: normalized.status },
          { type: 'text', text: normalized.deadline_at },
          { type: 'text', text: normalized.target }
        ]
      }
    ]
  }
};

return [{
  json: {
    ok: true,
    statusCode: 200,
    normalized,
    graphUrl: `https://graph.facebook.com/${graphVersion}/${phoneNumberId}/messages`,
    requestBody
  }
}];

const full = $input.first().json || {};
const statusCode = Number(full.statusCode || full.code || 502);
const body = full.body || {};
const ok = statusCode >= 200 && statusCode < 300 && !body.error;
const providerMessageId = body?.messages?.[0]?.id || body?.id || '';

return [{
  json: {
    ok,
    statusCode: ok ? 200 : statusCode,
    delivery_mode: 'whatsapp_template',
    delivery_result: ok ? 'sent' : `failed_http_${statusCode}`,
    provider_message_id: providerMessageId || null,
    error: ok ? null : (body?.error?.message || full.statusMessage || 'Template send failed')
  }
}];
